                </div>
                <div>
                    <label className="block text-right text-xs font-bold text-gray-400 mb-1">سعر الجملة (للسيرية)</label>
                    <input type="number" value={price || ''} onChange={e => setPrice(Number(e.target.value))} placeholder="0" className="w-full p-3 bg-gray-50 dark:bg-gray-700 border-none rounded-2xl text-center font-black text-primary focus:ring-2 focus:ring-primary/50" />
                </div>
            </div>
        </div>

        {/* 3. تفاصيل السيرية والعدد */}
        <div className="bg-blue-50 dark:bg-blue-900/10 rounded-3xl p-5 border border-blue-100 dark:border-blue-800/50 space-y-4">
            <div className="flex items-center justify-end gap-2 mb-2">
                <h3 className="font-black text-blue-800 dark:text-blue-300 text-sm">تفاصيل السيرية والمخزون</h3>
                <CubesStackIcon className="w-5 h-5 text-blue-600" />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-right text-[10px] font-bold text-blue-600/60 dark:text-blue-400/60 mb-1">إجمالي عدد السيريات (المخزون)</label>
                    <input type="number" value={stock || ''} onChange={e => setStock(Number(e.target.value))} placeholder="0" className="w-full p-3 bg-white dark:bg-gray-800 border-none rounded-2xl text-center font-bold text-gray-800 dark:text-white" />
                </div>
                <div>
                    <label className="block text-right text-[10px] font-bold text-blue-600/60 dark:text-blue-400/60 mb-1">عدد القطع في السيرية الواحدة</label>
                    <input type="number" value={seriesCount || ''} onChange={e => setSeriesCount(Number(e.target.value))} placeholder="0" className="w-full p-3 bg-white dark:bg-gray-800 border-none rounded-2xl text-center font-bold text-gray-800 dark:text-white" />
                </div>
            </div>

            <div>
                <label className="block text-right text-[10px] font-bold text-blue-600/60 dark:text-blue-400/60 mb-1">قياسات السيرية (مثال: S-M-L-XL)</label>
                <input type="text" value={seriesSizes} onChange={e => setSeriesSizes(e.target.value)} placeholder="ادخل القياسات المتوفرة" className="w-full p-3 bg-white dark:bg-gray-800 border-none rounded-2xl text-right font-bold text-gray-800 dark:text-white" />
            </div>
        </div>

        {/* 4. الوصف ومعلومات البكج */}
        <div className="bg-white dark:bg-gray-800 rounded-3xl p-5 shadow-sm border border-gray-100 dark:border-gray-700 space-y-4">
            <div>
                <label className="block text-right text-xs font-bold text-gray-400 mb-1">معلومات البكج (تظهر للمسوق بشكل بارز)</label>
                <textarea value={marketingDescription} onChange={e => setMarketingDescription(e.target.value)} placeholder="مثال: بكج توفيري يحتوي على 3 ألوان مختلفة..." className="w-full p-3 bg-gray-50 dark:bg-gray-700 border-none rounded-2xl text-right dark:text-white h-24 resize-none focus:ring-2 focus:ring-primary/50" />
            </div>

            <div>
                <label className="block text-right text-xs font-bold text-gray-400 mb-1">وصف المنتج (تفاصيل إضافية)</label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} placeholder="اكتب مواصفات المنتج هنا..." className="w-full p-3 bg-gray-50 dark:bg-gray-700 border-none rounded-2xl text-right dark:text-white h-24 resize-none focus:ring-2 focus:ring-primary/50" />
            </div>
        </div>

        {/* 5. تسعير المسوق (اختياري لكن مفيد) */}
        <div className="bg-green-50 dark:bg-green-900/10 rounded-3xl p-5 border border-green-100 dark:border-green-800/50">
            <label className="block text-right font-black text-green-800 dark:text-green-300 mb-3 text-sm">نطاق سعر البيع المقترح (للزبون)</label>
            <div className="grid grid-cols-2 gap-4">
                <input type="number" value={maxSellPrice || ''} onChange={e => setMaxSellPrice(Number(e.target.value))} placeholder="أعلى سعر" className="w-full p-3 bg-white dark:bg-gray-800 border-none rounded-2xl text-center font-bold" />
                <input type="number" value={minSellPrice || ''} onChange={e => setMinSellPrice(Number(e.target.value))} placeholder="أقل سعر" className="w-full p-3 bg-white dark:bg-gray-800 border-none rounded-2xl text-center font-bold" />
            </div>
            <p className="text-[10px] text-green-600 dark:text-green-400 text-right mt-2 font-bold">* يساعد هذا الحقل المسوق على معرفة هامش ربحه المتوقع.</p>
        </div>

      </div>

      {/* الأزرار الثابتة في الأسفل */}
      <div className="fixed bottom-0 left-0 right-0 p-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-t dark:border-gray-800 z-50">
          <div className="max-w-2xl mx-auto flex gap-3">
              <button onClick={onCancel} className="flex-1 py-4 bg-gray-100 dark:bg-gray-800 text-gray-500 rounded-2xl font-black active:scale-95 transition-all">إلغاء</button>
              {productToEdit && (
                  <button onClick={handleDeleteClick} className="w-14 h-14 flex items-center justify-center bg-red-50 text-red-500 rounded-2xl active:scale-95 transition-all">
                      <TrashIcon className="w-6 h-6" />
                  </button>
              )}
              <button onClick={handleSubmit} className="flex-[2] py-4 bg-primary text-white rounded-2xl font-black shadow-lg shadow-primary/30 active:scale-95 transition-all">
                  {productToEdit ? 'حفظ التعديلات' : 'نشر المنتج الآن'}
              </button>
          </div>
      </div>
    </div>
  );
};

export default AdminProductEditPage;
